import{_ as t,o,c as a,a3 as n}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Module Architecture","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Module Architecture | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/architecture/module-architecture"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Module Architecture | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/architecture/module-architecture"}]]},"headers":[],"relativePath":"architecture/module-architecture.md","filePath":"architecture/module-architecture.md","lastUpdated":1784743690000}'),i={name:"architecture/module-architecture.md"};function r(d,e,s,l,c,u){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="module-architecture" tabindex="-1">Module Architecture <a class="header-anchor" href="#module-architecture" aria-label="Permalink to &quot;Module Architecture&quot;">​</a></h1><p>SaleOS follows a <strong>modular architecture</strong>. Every business capability must be developed as an <strong>independent module</strong>.</p><p>This document is the required convention for all future development. It establishes ownership boundaries and communication rules so the platform can grow into a full ERP without redesigning the frozen foundation.</p><blockquote><p><strong>Scope</strong></p><p>This is an architectural convention and development guideline. It does not change existing source code, billing logic, marketplace implementation, or database schema by itself. Implement new modules against this standard when they are built.</p></blockquote><h2 id="what-is-a-module" tabindex="-1">What is a module? <a class="header-anchor" href="#what-is-a-module" aria-label="Permalink to &quot;What is a module?&quot;">​</a></h2><p>A module is a self-contained business domain (for example Leads, Tasks, Calendar, or Meetings) that:</p><ul><li>Is registered in the marketplace catalog</li><li>Is licensed at the workspace level (<code>module:{slug}</code>)</li><li>Is authorized with Spatie permissions (<code>can:{slug}.{action}</code>)</li><li>Ships backend, frontend, tests, and documentation together</li></ul><p>Modules are <strong>not</strong> PHP packages, Laravel Modules plugins, or auto-discovered plugins. Code lives in the existing flat application layout. See the <a href="/developer-guide/module-development">Module Development Standard</a>.</p><h2 id="ownership-—-what-each-module-owns" tabindex="-1">Ownership — what each module owns <a class="header-anchor" href="#ownership-—-what-each-module-owns" aria-label="Permalink to &quot;Ownership — what each module owns&quot;">​</a></h2><p>Each module should own its own:</p><table tabindex="0"><thead><tr><th>Concern</th><th>Examples</th></tr></thead><tbody><tr><td>Database migrations</td><td>Tables, columns, and indexes for that domain</td></tr><tr><td>Models</td><td>Eloquent models with tenant scoping</td></tr><tr><td>Services</td><td>Domain services and business workflows</td></tr><tr><td>API routes</td><td>Tenant (and, when needed, central) API endpoints</td></tr><tr><td>Frontend pages / components</td><td>List pages, forms, drawers, module-specific UI</td></tr><tr><td>Permissions</td><td>Spatie permission vocabulary for the module</td></tr><tr><td>Settings</td><td>Module-specific settings keys when applicable</td></tr><tr><td>Documentation</td><td>User, developer, API, deployment, and CHANGELOG updates</td></tr><tr><td>Tests</td><td>Pest feature tests and Playwright <code>test:e2e:{slug}</code></td></tr><tr><td>Seeders</td><td>Local/demo seeders when applicable (production catalog/RBAC uses data migrations)</td></tr></tbody></table><p>If a capability does not fit cleanly inside one module’s ownership, treat that as a design smell: either expand the correct module’s boundary or introduce a dedicated module.</p><h2 id="boundaries-and-communication" tabindex="-1">Boundaries and communication <a class="header-anchor" href="#boundaries-and-communication" aria-label="Permalink to &quot;Boundaries and communication&quot;">​</a></h2><p>Modules must <strong>not</strong> contain another module’s business logic.</p><table tabindex="0"><thead><tr><th>Allowed</th><th>Not allowed</th></tr></thead><tbody><tr><td>Call another module through a <strong>contract</strong> or <strong>service</strong> API</td><td>Copy or embed another module’s domain rules</td></tr><tr><td>Depend on shared platform services (auth, tenancy, audit, settings)</td><td>Reach into another module’s private models/controllers for business decisions</td></tr><tr><td>Emit domain events that other modules may listen to</td><td>Hard-code unrelated module UI or permission checks inside your module</td></tr><tr><td>Declare an explicit dependency (see <a href="./module-dependencies">Module Dependencies</a>)</td><td>Assume another module is always installed without declaring it</td></tr></tbody></table><p>Cross-module integration should go through well-defined services, contracts, events, or documented APIs — never through informal coupling.</p><h2 id="relationship-to-the-platform-foundation" tabindex="-1">Relationship to the platform foundation <a class="header-anchor" href="#relationship-to-the-platform-foundation" aria-label="Permalink to &quot;Relationship to the platform foundation&quot;">​</a></h2><p>The platform foundation is <strong>frozen</strong> (authentication, tenancy, RBAC, billing/marketplace shell, settings, audit). Modules extend that foundation; they do not replace it.</p><ul><li>Licensing gate: <code>module:{slug}</code></li><li>Authorization gate: Spatie <code>can:{permission}</code></li><li>Reference implementation: <strong>Leads</strong> (and <strong>Tasks</strong> for a second completed example)</li></ul><p>See <a href="/getting-started/platform-freeze">Platform Architecture Freeze</a>.</p><h2 id="development-convention" tabindex="-1">Development convention <a class="header-anchor" href="#development-convention" aria-label="Permalink to &quot;Development convention&quot;">​</a></h2><p>All future modules must follow the same architecture and conventions.</p><p>Every new module should:</p><ol><li>Be <strong>self-contained</strong></li><li><strong>Own its resources</strong> (migrations, models, services, routes, UI, permissions, settings, docs, tests, seeders when applicable)</li><li><strong>Declare dependencies</strong> when required (<a href="./module-dependencies">Module Dependencies</a>)</li><li><strong>Avoid coupling</strong> with unrelated modules</li><li>Be compatible with future <strong>marketplace / module licensing</strong> (<a href="./module-licensing">Module Licensing</a>)</li><li>Follow existing <strong>coding standards</strong> and project structure (<a href="/developer-guide/module-development-guide">Module Development Guide</a>)</li></ol><p>This is a <strong>development guideline</strong> for engineers. Completeness is measured by the <a href="/developer-guide/module-development#definition-of-done">Definition of Done</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./module-dependencies">Module Dependencies</a></li><li><a href="./module-licensing">Module Licensing</a></li><li><a href="/developer-guide/module-development">Module Development Standard</a></li><li><a href="/developer-guide/entitlements">Entitlements</a></li><li><a href="/getting-started/product-roadmap">Product Roadmap</a></li></ul>',27)])])}const p=t(i,[["render",r]]);export{m as __pageData,p as default};
